// Validate incoming payload
const body = $input.first().json.body || $input.first().json;

if (!body.launch_id || !body.user_id) {
  throw new Error('Missing required fields: launch_id, user_id');
}

return [{
  json: {
    launch_id: body.launch_id,
    user_id: body.user_id
  }
}];

const launch = $('Load Launch').first().json;
const signals = $('Fetch Competitor Signals').all().map(i => i.json);

// Capture initial messaging/positioning state
const messagingSignals = signals.filter(s => s.signal_type === 'messaging');
const positioningSignals = signals.filter(s => s.signal_type === 'positioning');

const initialMessaging = {
  snapshot_date: new Date().toISOString(),
  competitor_messaging_signals: messagingSignals.length,
  top_themes: messagingSignals.slice(0, 5).map(s => s.title)
};

const initialPositioning = {
  snapshot_date: new Date().toISOString(),
  competitor_positioning_signals: positioningSignals.length,
  top_themes: positioningSignals.slice(0, 5).map(s => s.title)
};

// Compute initial readiness estimate
const hasCompetitors = (launch.competitor_names || []).length > 0;
const hasSignals = signals.length > 0;
const daysUntil = Math.round((new Date(launch.target_launch_date).getTime() - Date.now()) / (1000 * 60 * 60 * 24));

let readinessScore = 30; // base
if (hasCompetitors) readinessScore += 15;
if (hasSignals) readinessScore += 15;
if (messagingSignals.length >= 3) readinessScore += 10;
if (positioningSignals.length >= 3) readinessScore += 10;
if (daysUntil > 14) readinessScore += 10;
readinessScore = Math.min(readinessScore, 100);

return [{
  json: {
    launch_id: launch.id,
    user_id: launch.user_id,
    initial_messaging: JSON.stringify(initialMessaging),
    initial_positioning: JSON.stringify(initialPositioning),
    readiness_score: readinessScore,
    readiness_breakdown: JSON.stringify({
      competitor_landscape: hasCompetitors ? 60 : 20,
      messaging_readiness: messagingSignals.length >= 3 ? 70 : 30,
      market_timing: daysUntil > 14 ? 80 : 40,
      objection_coverage: 30,
      battlecard_freshness: hasSignals ? 50 : 20
    }),
    signal_count: signals.length
  }
}];
